public int makeChocolate(int small, int big, int goal) {
    int bigBars = goal / 5;
    int remaining = goal % 5;
    if (bigBars > big) {
        bigBars = big;
        remaining = goal - bigBars * 5;
    }
    if (remaining > small) {
        return -1;
    } else {
        return remaining;
    }
}

