Code:
public boolean canBalance(int[] nums) {
    int numsSum = 0;
    for (int i = 0; i < nums.length; i++) {
        numsSum += nums[i];
    }
    int leftSum = 0;
    for (int i = 0; i < nums.length; i++) {
        numsSum -= nums[i];
        if (leftSum == numsSum) {
            return true;
        }
        leftSum += nums[i];
    }
    return false;
}

public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int prev = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] != prev) {
            prev = nums[i];
        } else if (nums[i] % 10 != 0) {
            nums[i] = prev;
        }
    }

    return nums;
}

